// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;


contract TransactionTest {


    function sendETH(address payable receiver, uint256) external payable {
        require(msg.value > 0, "No ETH sent");

        (bool success, ) = receiver.call{value: msg.value}("");
        require(success, "ETH transfer failed");
    }

}




contract A {
    address public contractB;
    address public addressA;

    function registerB(address _b) external {
        contractB = _b;
    }

    function myAddress() external{
        addressA = address(this);
    }
}


interface IA {
    function registerB(address _b) external;
    function myAddress() external;
}

contract B {
    address public contractA;

    function getAddress() private{
        
    }

    constructor(address _a) {
        contractA = _a;
    }
}


contract Receive{}

